clc;
clear;
close all;

%% LOAD DATASET
load('SubB_6chan_2LR.mat');   % Replace with your file name

% Dataset:
% EEGDATA = 6 x 1000 x 162
% LABELS  = 162 x 1

%% PREPROCESSING

EEGDATA = double(EEGDATA);
EEGDATA(~isfinite(EEGDATA)) = 0;

Fs = 250;

%% FILTERING

EEG_filtered = zeros(size(EEGDATA));

for trial = 1:size(EEGDATA,3)

    EEG_filtered(:,:,trial) = ...
        bandpass(EEGDATA(:,:,trial)',[8 30],Fs)';

end

%% FEATURE EXTRACTION

features = [];

for trial = 1:size(EEG_filtered,3)

    feature_vector = [];

    for ch = 1:6

        signal = EEG_filtered(ch,:,trial);

        feature_vector = [feature_vector ...
            mean(signal) ...
            std(signal) ...
            var(signal) ...
            max(signal) ...
            min(signal)];

    end

    features = [features; feature_vector];

end

%% PREPARE INPUTS

X = features';      % 30 x 162

Y = full(ind2vec(LABELS'));   % 2 x 162

%% CREATE ANN

net = patternnet(20);

net.divideParam.trainRatio = 0.70;
net.divideParam.valRatio   = 0.15;
net.divideParam.testRatio  = 0.15;

%% TRAIN MODEL

[net,tr] = train(net,X,Y); %[output:2b0eb7e7]

%% PREDICTION

outputs = net(X);

[~,predicted] = max(outputs);

accuracy = ...
sum(predicted'==LABELS) ...
/ length(LABELS) * 100;

fprintf('\nAccuracy = %.2f %%\n',accuracy); %[output:74346421]

%% CONFUSION MATRIX

figure; %[output:4e4af251]
plotconfusion(Y,outputs); %[output:4e4af251]

%% SAVE MODEL

save('LeftRightHandANN.mat','net');

disp('Model Saved Successfully'); %[output:8e6ce79b]

